.calendar-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
    max-width: 1200px;
    margin: 0 auto;
}

.calendar-main {
    flex: 1;
    min-width: 0;
}

/* Month Navigation */
.month-nav {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
}

.month-label {
    flex: 1;
    text-align: center;
    margin: 0;
}

/* Team Filter */
.team-filter {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 6px;
}

.filter-checkbox {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    cursor: pointer;
    font-size: 0.9rem;
}

/* Calendar Grid */
.calendar-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 1px;
    background: #dee2e6;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.day-header {
    padding: 0.5rem;
    text-align: center;
    font-weight: 600;
    background: #e9ecef;
    font-size: 0.85rem;
}

.day-cell {
    min-height: 80px;
    padding: 0.4rem;
    background: #fff;
    cursor: pointer;
    transition: background-color 0.15s;
    display: flex;
    flex-direction: column;
}

.day-cell:hover {
    background: #f0f7ff;
}

.day-cell.day-outside {
    background: #f8f9fa;
    color: #adb5bd;
}

.day-cell.day-today {
    background: #e8f4fd;
    border: 2px solid #0d6efd;
}

.day-cell.day-selected {
    background: #cfe2ff;
}

.day-number {
    font-weight: 500;
    font-size: 0.9rem;
}

.event-dots {
    display: flex;
    flex-wrap: wrap;
    gap: 3px;
    margin-top: auto;
    align-items: center;
}

.event-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #0d6efd;
}

.event-dot:nth-child(2) {
    background: #198754;
}

.event-dot:nth-child(3) {
    background: #dc3545;
}

.more-events {
    font-size: 0.7rem;
    color: #6c757d;
}

/* Day Detail Panel */
.day-panel {
    width: 320px;
    flex-shrink: 0;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1rem;
    background: #fff;
    align-self: flex-start;
    max-height: calc(100vh - 4rem);
    overflow-y: auto;
}

.day-panel h4 {
    margin-bottom: 1rem;
    font-size: 1.1rem;
}

.no-events {
    color: #6c757d;
    font-style: italic;
}

.event-list {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    margin-bottom: 1rem;
}

.event-card {
    padding: 0.75rem;
    border: 1px solid #e9ecef;
    border-radius: 6px;
    background: #f8f9fa;
}

.event-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.event-time {
    font-size: 0.85rem;
    color: #495057;
}

.event-attendees {
    font-size: 0.8rem;
    color: #6c757d;
    margin-bottom: 0.5rem;
}

.new-event-btn {
    width: 100%;
}

/* New Event Form */
.new-event-form .form-group {
